import{c as l,Z as a,Q as d,j as u,g as t,n as o,o as n,m as s,av as c}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse('{"title":"Let the agent act autonomously","description":"With a Scoped session, the agent can buy, sell, claim, reinvest, and rebalance without per-action prompts.","frontmatter":{"title":"Let the agent act autonomously","description":"With a Scoped session, the agent can buy, sell, claim, reinvest, and rebalance without per-action prompts."},"headers":[],"relativePath":"guide/agent/autonomous.md","filePath":"guide/agent/autonomous.md","lastUpdated":1780199385000}'),h={name:"guide/agent/autonomous.md"};function p(g,e,m,y,b,v){const r=a("TaskMeta"),i=a("ExpectedResult");return d(),u("div",null,[e[1]||(e[1]=t("h1",{id:"let-the-agent-act-autonomously",tabindex:"-1"},[o("Let the agent act autonomously "),t("a",{class:"header-anchor",href:"#let-the-agent-act-autonomously","aria-label":'Permalink to "Let the agent act autonomously"'},"​")],-1)),n(r,{time:"~4 min",role:"Any signed-in user",needs:"A Scoped session granted (H3)"}),e[2]||(e[2]=s('<blockquote><p><strong>What you&#39;ll do:</strong> Grant a <strong>Scoped</strong> session, then watch the agent execute a small action on-chain without prompting you per trade.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>::: important Requires a Scoped session This flow only runs when you&#39;ve granted a <strong>Scoped</strong> session — see <a href="/guide/agent/set-tier">Set the agent&#39;s autonomy tier</a>. Without one, these actions fall back to a dashboard deep-link you must approve with your passkey. :::</p><h2 id="what-the-agent-can-do-autonomously" tabindex="-1">What the agent can do autonomously <a class="header-anchor" href="#what-the-agent-can-do-autonomously" aria-label="Permalink to &quot;What the agent can do autonomously&quot;">​</a></h2><ul><li><strong>Buy / Sell / Claim</strong> — <code>muhaven.position.buy</code>, <code>muhaven.position.sell</code>, <code>muhaven.position.claim</code> (claim needs a concrete epoch/escrow id). With a live Scoped session these submit autonomously and return a tx hash; without one they fall back to a dashboard deep-link you approve with your passkey.</li><li><strong>Auto-reinvest</strong> — the agent can automatically claim matured yield and buy more of a token (opt-in).</li><li><strong>Rebalance to targets</strong> — ask <strong>HavenBot</strong> to &quot;rebalance my portfolio to these targets&quot;. It uses the <strong>Auto-rebalance</strong> panel on <code>/portfolio</code>, then executes <strong>one atomic transaction</strong> (sells before buys) via your in-tab scoped session.</li></ul><div class="warning custom-block"><p class="custom-block-title">Two carve-outs to remember</p><ul><li>The standalone external MCP tool <code>muhaven.position.rebalance</code> is intentionally <strong>not implemented</strong> and returns <strong><code>not_implemented</code></strong>. Do rebalances through <strong>HavenBot / the Portfolio panel</strong>, not that tool.</li><li><strong><code>muhaven.cash.wrap</code> / <code>muhaven.cash.unwrap</code></strong> always go through a passkey <strong>dashboard deep-link</strong> — never silent autonomous submission.</li></ul></div><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Grant a <strong>Scoped</strong> session (<a href="/guide/agent/set-tier">H3</a>).</li><li>Ask the agent to make a <strong>small buy</strong> (or set up auto-reinvest, or a rebalance to targets).</li><li>Watch it execute — transactions take ~30–60s and gas is sponsored.</li><li>Verify the result in <a href="/guide/investor/activity">Activity</a> and via <code>muhaven.read.activity</code>.</li></ol><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',9)),n(i,null,{default:c(()=>[...e[0]||(e[0]=[o(" The agent executes ",-1),t("strong",null,"without a per-action prompt",-1),o(" and returns a ",-1),t("strong",null,"tx hash",-1),o(". After ~30–60s the action appears in ",-1),t("a",{href:"/guide/investor/activity"},"Activity",-1),o(" and in ",-1),t("code",null,"muhaven.read.activity",-1),o(". ",-1)])]),_:1}),e[3]||(e[3]=s('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Action returns a deep-link instead of running</td><td>No live Scoped session — grant one in <a href="/guide/agent/set-tier">H3</a>.</td></tr><tr><td><code>muhaven.position.rebalance</code> returns <code>not_implemented</code></td><td>Expected — rebalance via HavenBot / the Portfolio panel instead.</td></tr><tr><td><code>muhaven.cash.wrap</code> / <code>muhaven.cash.unwrap</code> asks for your passkey</td><td>Expected — those always use a dashboard deep-link, never autonomous submission.</td></tr><tr><td>You want to stop everything now</td><td>Use the <a href="/guide/agent/pause">pause kill-switch</a>.</td></tr></tbody></table><p>→ Next: <a href="/guide/agent/deep-link-confirm">Approve an action via deep-link</a></p>',3))])}const _=l(h,[["render",p]]);export{k as __pageData,_ as default};
